// Lấy summary data
const input = $input.first().json;

// Item 1: Tổng số liệu từ summarize
const item1 = {
  MaVatTu: null,
  TenVatTu: null,
  dvt: null,
  TinhTrangHangHoa: null,
  PhieuKiemKe: null,
  tonCuoi: input.sum_tonCuoi,
  kiemKe: input.sum_kiemKe,
  chenhLech: input.sum_chenhLech,
  id: null,
  createdAt: null,
  updatedAt: null
};

// Item 2: Chữ ký
const item2 = {
  MaVatTu: 'ĐẠI DIỆN KIỂM KHO',
  TenVatTu: 'ĐẠI DIỆN KIỂM KÊ',
  dvt: 'QUẢN LÝ CHI NHÁNH',
  TinhTrangHangHoa: null,
  PhieuKiemKe: null,
  tonCuoi: null,
  kiemKe: null,
  chenhLech: 'KIỂM SOÁT NỘI BỘ',
  id: null,
  createdAt: null,
  updatedAt: null
};

return [
  { json: item1 },
  { json: item2 }
];

// Function — Run once for all items
// Lấy: 1) "phiên kiểm kê" từ header dạng KK-xxxx-xxxxx
//      2) "Ngày yêu cầu kiểm kê"
//      3) "khu vực kiểm kê"

const rows = $input.all().map(it => it.json);
const table = rows.map(r => Object.values(r).map(v => String(v ?? '').trim()));

const norm = s => String(s ?? '')
  .normalize('NFD').replace(/[\u0300-\u036f]/g,'')
  .toLowerCase().trim();
const raw = s => String(s ?? '').trim();

// ===== 1) PHIÊN kiểm kê từ header (KK-xxxx-xxxxx) =====
let phien = '';
if (table.length) {
  const upTo = Math.min(50, table.length);
  const lines = [];
  for (let i = 0; i < upTo; i++) lines.push(raw(table[i].join(' ')));
  const headerText = lines.join('  ');

  // Cố gắng match KK-xxxx-xxxxx
  let m = headerText.match(/\bkk[^0-9]*?(\d{4})[^0-9]*?(\d{5})\b/i);
  if (m) phien = `KK-${m[1]}-${m[2]}`;

  if (!phien) {
    const m2 = headerText.replace(/\s+/g,'').match(/\bkk(\d{9})\b/i);
    if (m2) phien = `KK-${m2[1].slice(0,4)}-${m2[1].slice(4)}`;
  }

  if (!phien) {
    outer:
    for (let i = 0; i < upTo; i++) {
      const row = table[i];
      for (let j = 0; j < row.length; j++) {
        const cell = row[j];
        if (!/kk/i.test(cell)) continue;
        let digits = (cell.match(/(\d+)/g) || []).join('');
        for (let k = j + 1; k < row.length && digits.length < 9; k++) {
          const tok = row[k];
          const nums = tok.match(/^\D*(\d+)/);
          if (!nums) break;
          digits += nums[1];
        }
        if (digits.length < 9 && i + 1 < table.length) {
          for (let k = 0; k < table[i+1].length && digits.length < 9; k++) {
            const tok = table[i+1][k];
            const nums = tok.match(/^\D*(\d+)/);
            if (!nums) continue;
            digits += nums[1];
          }
        }
        if (digits.length >= 9) {
          digits = digits.slice(0,9);
          phien = `KK-${digits.slice(0,4)}-${digits.slice(4)}`;
          break outer;
        }
      }
    }
  }

  if (!phien) {
    const compact = headerText.replace(/[^A-Za-z0-9]+/g,'').toLowerCase();
    const m3 = compact.match(/kk(\d{9})/i);
    if (m3) phien = `KK-${m3[1].slice(0,4)}-${m3[1].slice(4)}`;
  }
}

// ===== 2) "Ngày yêu cầu kiểm kê" + 3) "khu vực kiểm kê" =====
const tokens = {
  ngayYC: [
    'ngay yeu cau kiem ke',
    'ngay yeu cau',
    'ngay yc kiem ke',
    'requested date',
    'request date',
    'date requested'
  ],
  khu: [
    'khu vuc kiem ke',
    'khu vuc',
    'khu vuc kk',
    'area'
  ],
};
const hasToken = (s, list) => list.some(t => norm(s).includes(t));
const pickAfterSep = s => {
  const mm = String(s).match(/[:\-–]\s*(.+)$/);
  return mm ? raw(mm[1]) : '';
};
const rightCell = (vals, j) => {
  for (let k = j + 1; k < vals.length; k++) { const v = raw(vals[k]); if (v) return v; }
  return '';
};
const nextRowFirst = (tbl, i) => {
  if (i + 1 >= tbl.length) return '';
  const vals = tbl[i + 1];
  for (let k = 0; k < vals.length; k++) { const v = raw(vals[k]); if (v) return v; }
  return '';
};

let ngayYC = '';
let khu = '';

// theo tiêu đề cột
if (table.length) {
  const header = table[0].map(raw);
  const idxBy = lists => {
    for (let j = 0; j < header.length; j++) if (hasToken(header[j], lists)) return j;
    return -1;
  };
  const colNgayYC = idxBy(tokens.ngayYC);
  const colKhu    = idxBy(tokens.khu);

  const firstBelow = col => {
    if (col < 0) return '';
    for (let i = 1; i < table.length; i++) {
      const v = raw(table[i][col]); if (v) return v;
    }
    return '';
  };
  if (!ngayYC) ngayYC = firstBelow(colNgayYC);
  if (!khu)    khu    = firstBelow(colKhu);
}

// quét nhãn:giá trị
if (!ngayYC || !khu) {
  outer2:
  for (let i = 0; i < table.length; i++) {
    const row = table[i];
    for (let j = 0; j < row.length; j++) {
      const cell = raw(row[j]);
      if (!cell) continue;
      if (!ngayYC && hasToken(cell, tokens.ngayYC)) {
        ngayYC = pickAfterSep(cell) || rightCell(row, j) || nextRowFirst(table, i);
      }
      if (!khu && hasToken(cell, tokens.khu)) {
        khu = pickAfterSep(cell) || rightCell(row, j) || nextRowFirst(table, i);
      }
      if (ngayYC && khu) break outer2;
    }
  }
}

// ===== Output 3 item =====
return [
  {
    json: {
      'date': ngayYC || '',
      'session': phien || '',
      'zone': khu || ''
    }
  }
];

// Lấy response từ HTTP Request
const response = $input.first().json;

// Lấy array files
const files = response.files || [];

// Tách mỗi file thành 1 item riêng
return files.map(file => ({
  json: file
}));

// Mode: Run once for all items
const names = $input.all().map(item => item.json.name);

// Tạo YAML format
const yaml = names.map(name => `- "${name}"`).join('\n');

return [{ json: { yaml, names } }];

